{"content": "     1|#!/usr/bin/env node
     2|/**
     3| * jref CLI - Main Entry Point
     4| * Optimized Development Prompt CLI tool for interacting with JSON project snapshots
     5| * Designed for both human developers and AI agents
     6| */
     7|import { registerBuiltinCommands, registry } from './utils/command.js';
     8|import { readFromInput, isStdinPiped } from './utils/input.js';
     9|import { printError, printHeader, exit } from './utils/output.js';
    10|const VERSION = '1.0.0';
    11|/**
    12| * Parse global CLI options
    13| */
    14|function parseGlobalOptions(args) {
    15|    const options = {};
    16|    const remainingArgs = [];
    17|    for (let i = 0; i < args.length; i++) {
    18|        const arg = args[i];
    19|        switch (arg) {
    20|            case '--json':
    21|            case '-j':
    22|                options.json = true;
    23|                break;
    24|            case '--silent':
    25|            case '-s':
    26|                options.silent = true;
    27|                break;
    28|            case '--raw':
    29|            case '-r':
    30|                options.raw = true;
    31|                break;
    32|            case '--help':
    33|            case '-h':
    34|                options.help = true;
    35|                break;
    36|            case '--version':
    37|            case '-v':
    38|                options.version = true;
    39|                break;
    40|            default:
    41|                remainingArgs.push(arg);
    42|        }
    43|    }
    44|    return { remainingArgs, options };
    45|}
    46|/**
    47| * Print global help
    48| */
    49|function printGlobalHelp(options = {}) {
    50|    if (options.json) {
    51|        console.log(JSON.stringify({
    52|            name: 'jref',
    53|            version: VERSION,
    54|            description: 'CLI tool to interact with JSON project snapshots',
    55|            commands: registry.getAllCommands()
    56|        }));
    57|        return;
    58|    }
    59|    printHeader(options);
    60|    console.log('USAGE:\n');
