    70|    console.log('  --json, -j      Output in JSON format (for AI agents)');
    71|    console.log('  --silent, -s    Suppress all progress and decorative output');
    72|    console.log('  --raw, -r       Raw output mode (no formatting, for AI agents)');
    73|    console.log('  --help, -h      Show this help message');
    74|    console.log('  --version       Show version information');
