    85|    console.log();
    86|    console.log('  # Query a specific file (AI-friendly)');
    87|    console.log('  jref query --path "src/main.ts" --raw snapshot.json');
    88|    console.log();
    89|    console.log('  # Check if local directory matches snapshot');
    90|    console.log('  jref reconstruct --directory ./my-project snapshot.json');
    91|    console.log();
    92|    console.log('  # Pipe input support');
    93|    console.log('  cat snapshot.json | jref inspect');
    94|    console.log('  cat snapshot.json | jref search "TODO"');
