    99|/**
   100| * Print version
   101| */
   102|function printVersion(options = {}) {
   103|    if (options.json) {
   104|        console.log(JSON.stringify({ version: VERSION }));
   105|    }
   106|    else {
   107|        console.log(`jref v${VERSION}`);
   108|    }
   109|}
   110|/**
   111| * Main CLI handler
   112| */
   113|async function main() {
   114|    const args = process.argv.slice(2);
   115|    // Parse global options
   116|    const { remainingArgs, options } = parseGlobalOptions(args);
   117|    // Register commands
   118|    await registerBuiltinCommands();
   119|    // Handle version flag
   120|    if (options.version) {
   121|        printVersion(options);
   122|        exit(0);
   123|        return;
   124|    }
   125|    // Handle help flag
   126|    if (options.help || remainingArgs.length === 0) {
   127|        printGlobalHelp(options);
   128|        exit(0);
   129|        return;
   130|    }
   131|    // Get command name
   132|    const commandName = remainingArgs[0];
   133|    const commandArgs = remainingArgs.slice(1);
   134|    // Find command
   135|    const command = registry.get(commandName);
   136|    if (!command) {
   137|        printError(`Unknown command: ${commandName}`, options);
   138|        console.log(`Run 'jref --help' for available commands.`);
   139|        exit(1);
   140|        return;
   141|    }
   142|    // Handle help for specific command
   143|    if (commandArgs.includes('--help') || commandArgs.includes('-h')) {
   144|        command.printHelp(options);
   145|        exit(0);
   146|        return;
   147|    }
   148|    // Check for stdin input
   149|    const stdinIsPipe = isStdinPiped();
   150|    let stdinData = '';
   151|    if (stdinIsPipe) {
   152|        stdinData = await readFromInput();
   153|    }
   154|    // Create command context
   155|    const context = {
   156|        stdin: stdinData,
   157|        stdinIsPipe
   158|    };
   159|    // Execute command
   160|    try {
   161|        const result = await command.execute(commandArgs, options, context);
   162|        exit(result.exitCode);
   163|    }
   164|    catch (err) {
   165|        printError(`Fatal error: ${err.message}`, options);
   166|        exit(1);
   167|    }
   168|}
   169|// Export for testing
   170|export { main, registerBuiltinCommands, registry };
   171|// Run if executed directly
   172|main().catch((err) => {
   173|    console.error('Fatal error:', err);
   174|    process.exit(1);
   175|});
