{"content": "     1|/**
     2| * Command Base Class
     3| * Abstract base for all CLI commands following the Command pattern
     4| */
     5|import { printError, printOutput } from './output.js';
     6|export class Command {
     7|    /**
     8|     * Get the snapshot from context, loading if necessary
     9|     */
    10|    async getSnapshot(context) {
    11|        if (context.snapshot) {
    12|            return context.snapshot;
    13|        }
    14|        const { loadSnapshot } = await import('./streaming-json.js');
    15|        const snapshot = await loadSnapshot(context.stdin);
    16|        return snapshot;
    17|    }
    18|    /**
    19|     * Format and print command result
    20|     */
    21|    print(data, options) {
    22|        printOutput(data, options);
    23|    }
    24|    /**
    25|     * Print error and return error result
    26|     */
    27|    error(message, options, exitCode = 1) {
    28|        printError(message, options);
    29|        return {
    30|            success: false,
    31|            exitCode,
    32|            error: message
    33|        };
    34|    }
    35|    /**
    36|     * Create success result
    37|     */
    38|    success(output) {
    39|        return {
    40|            success: true,
    41|            exitCode: 0,
    42|            output
    43|        };
    44|    }
    45|    /**
    46|     * Print help for this command
    47|     */
    48|    printHelp(options = {}) {
    49|        const { name, description, usage, examples } = this.definition;
    50|        if (options.json) {
    51|            this.print({
    52|                command: name,
    53|                description,
    54|                usage,
    55|                examples
    56|            }, options);
    57|            return;
    58|        }
    59|        console.log(`\n${name.toUpperCase()} COMMAND`);
    60|        console.log('='.repeat(50));
    61|        console.log(`\nDescription: ${description}`);
    62|        console.log(`\nUsage: ${usage}`);
    63|        console.log('\nExamples:');
    64|        for (const example of examples) {
    65|            console.log(`  ${example}`);
    66|        }
    67|        console.log();
    68|    }
    69|}
    70|/**
    71| * Command Registry
    72| * Manages registration and lookup of available commands
    73| */
    74|export class CommandRegistry {
    75|    commands = new Map();
    76|    /**
    77|     * Register a command
    78|     */
    79|    register(command) {
    80|        this.commands.set(command.definition.name, command);
    81|    }
    82|    /**
    83|     * Get a command by name
    84|     */
    85|    get(name) {
    86|        return this.commands.get(name);
    87|    }
    88|    /**
    89|     * Get all registered command names
    90|     */
    91|    getCommandNames() {
    92|        return Array.from(this.commands.keys());
    93|    }
    94|    /**
    95|     * Check if command exists
    96|     */
    97|    has(name) {
    98|        return this.commands.has(name);
    99|    }
   100|    /**
   101|     * Get all commands with their definitions
   102|     */
   103|    getAllCommands() {
   104|        return Array.from(this.commands.values()).map((cmd) => cmd.definition);
   105|    }
   106|}
   107|// Global registry instance
   108|export const registry = new CommandRegistry();
   109|/**
   110| * Register all built-in commands
   111| */
   112|export async function registerBuiltinCommands() {
   113|    const { InspectCommand } = await import('../commands/inspect.js');
   114|    const { SearchCommand } = await import('../commands/search.js');
   115|    const { ExtractCommand } = await import('../commands/extract.js');
   116|    const { QueryCommand } = await import('../commands/query.js');
   117|    const { ReconstructCommand } = await import('../commands/reconstruct.js');
   118|    const { UICommand } = await import('../commands/ui.js');
   119|    const { PatchCommand } = await import('../commands/patch.js');
   120|    const { ServeCommand } = await import('../commands/serve.js');
   121|    const { DiffCommand } = await import('../commands/diff.js');
   122|    const { PackCommand } = await import('../commands/pack.js');
   123|    const { SummarizeCommand } = await import('../commands/summarize.js');
   124|    registry.register(new InspectCommand());
   125|    registry.register(new SearchCommand());
   126|    registry.register(new ExtractCommand());
   127|    registry.register(new QueryCommand());
   128|    registry.register(new ReconstructCommand());
   129|    registry.register(new UICommand());
   130|    registry.register(new PatchCommand());
   131|    registry.register(new ServeCommand());
   132|    registry.register(new DiffCommand());
   133|    registry.register(new PackCommand());
   134|    registry.register(new SummarizeCommand());
   135|}
