{"content": "     1|import { Command } from '../utils/command.js';
     2|import { readFileSync, readdirSync, lstatSync, existsSync } from 'fs';
     3|import { join, relative, basename } from 'path';
     4|import ignore from 'ignore';
     5|export class PackCommand extends Command {
     6|    definition = {
     7|        name: 'pack',
     8|        description: 'Create a snapshot from a local directory',
     9|        usage: 'jref pack [directory] [options]',
    10|        examples: [
    11|            'jref pack . > snapshot.json',
    12|            'jref pack ./my-project --instruction "Follow these rules" > snapshot.json'
    13|        ]
    14|    };
    15|    async execute(args, options, _context) {
    16|        try {
    17|            const { flags, targetDir } = this.parseArgs(args);
    18|            const rootDir = targetDir || process.cwd();
    19|            if (!existsSync(rootDir)) {
    20|                return this.error(`Directory not found: ${rootDir}`, options);
    21|            }
    22|            const files = {};
    23|            const ig = ignore();
    24|            // Load .gitignore if it exists
    25|            const gitignorePath = join(rootDir, '.gitignore');
    26|            if (existsSync(gitignorePath)) {
    27|                ig.add(readFileSync(gitignorePath, 'utf8'));
    28|            }
    29|            // Always ignore .git
    30|            ig.add('.git');
    31|            const treeLines = [basename(rootDir) + '/'];
    32|            this.walk(rootDir, rootDir, ig, files, treeLines, '');
    33|            const snapshot = {
    34|                directoryStructure: treeLines.join('\n'),
    35|                files,
    36|                instruction: flags.instruction || undefined,
    37|                fileSummary: flags.summary || undefined
    38|            };
    39|            const output = JSON.stringify(snapshot, null, 2);
    40|            // If --json flag is set or silent, we don't print decoration
    41|            if (options.json || options.silent) {
    42|                return this.success(output);
    43|            }
    44|            console.log(output);
    45|            return this.success(output);
    46|        }
    47|        catch (err) {
    48|            return this.error(`Pack failed: ${err.message}`, options);
    49|        }
    50|    }
    51|    walk(currentDir, rootDir, ig, files, treeLines, prefix) {
    52|        const entries = readdirSync(currentDir).sort();
    53|        entries.forEach((entry, index) => {
    54|            const fullPath = join(currentDir, entry);
    55|            const relPath = relative(rootDir, fullPath);
    56|            if (ig.ignores(relPath))
    57|                return;
    58|            const isLast = index === entries.length - 1;
    59|            const stats = lstatSync(fullPath);
    60|            const isDir = stats.isDirectory();
    61|            // Add to tree
    62|            treeLines.push(`${prefix}${isLast ? '└── ' : '├── '}${entry}${isDir ? '/' : ''}`);
    63|            if (isDir) {
    64|                this.walk(fullPath, rootDir, ig, files, treeLines, prefix + (isLast ? '    ' : '│   '));
    65|            }
    66|            else {
    67|                files[relPath] = readFileSync(fullPath, 'utf8');
    68|            }
    69|        });
    70|    }
    71|    parseArgs(args) {
    72|        const flags = {};
    73|        let targetDir;
    74|        for (let i = 0; i < args.length; i++) {
    75|            const arg = args[i];
    76|            if (arg === '--instruction') {
    77|                flags.instruction = args[++i];
    78|            }
    79|            else if (arg === '--summary') {
    80|                flags.summary = args[++i];
    81|            }
    82|            else if (!arg.startsWith('-')) {
    83|                targetDir = arg;
    84|            }
    85|        }
    86|        return { flags, targetDir };
    87|    }
    88|}
