{"content": "     1|/**
     2| * Inspect Command
     3| * Views directoryStructure and metadata without loading entire file into memory
     4| * Supports streaming for large JSON snapshots
     5| */
     6|import { Command } from '../utils/command.js';
     7|import { loadSnapshot, calculateMetadata } from '../utils/streaming-json.js';
     8|import { printTable, printHeader } from '../utils/output.js';
     9|export class InspectCommand extends Command {
    10|    definition = {
    11|        name: 'inspect',
    12|        description: 'View directoryStructure and metadata without loading entire file',
    13|        usage: 'jref inspect [options] [file]',
    14|        examples: [
    15|            'jref inspect snapshot.json',
    16|            'jref inspect --metadata snapshot.json',
    17|            'jref inspect --structure snapshot.json',
    18|            'cat snapshot.json | jref inspect',
    19|            'jref inspect --json snapshot.json'
    20|        ]
    21|    };
    22|    async execute(args, options, context) {
    23|        try {
    24|            const { flags, filePath } = this.parseArgs(args);
    25|            // Load snapshot from file or stdin
    26|            const snapshot = await loadSnapshot(filePath ? await this.readFile(filePath) : context.stdin);
    27|            const metadata = calculateMetadata(snapshot);
    28|            // Show header in human mode
    29|            if (!options.silent && !options.raw && !options.json) {
    30|                printHeader(options);
    31|            }
    32|            // Determine what to show
    33|            const showMeta = flags.metadata || false;
    34|            const showStructure = flags.structure || false;
    35|            const showFiles = flags.files || false;
    36|            const showSummary = flags.summary || false;
    37|            // If no specific flags, show everything
    38|            const showAll = !showMeta && !showStructure && !showFiles && !showSummary;
    39|            if (options.json) {
    40|                const result = {};
    41|                if (showAll || showMeta) {
    42|                    result.metadata = metadata;
    43|                }
    44|                if (showAll || showStructure) {
    45|                    result.directoryStructure = snapshot.directoryStructure;
    46|                }
    47|                if (showAll || showFiles) {
    48|                    result.filePaths = Object.keys(snapshot.files);
    49|                }
    50|                if (showAll || showSummary) {
    51|                    if (snapshot.instruction)
    52|                        result.instruction = snapshot.instruction;
    53|                    if (snapshot.fileSummary)
    54|                        result.fileSummary = snapshot.fileSummary;
    55|                    if (snapshot.userProvidedHeader)
    56|                        result.userProvidedHeader = snapshot.userProvidedHeader;
    57|                }
    58|                this.print(result, options);
    59|            }
    60|            else {
    61|                // Human-readable output
    62|                if (showAll || showMeta) {
    63|                    this.printMetadata(metadata, options);
    64|                }
    65|                if (showAll || showStructure) {
    66|                    this.printStructure(snapshot.directoryStructure, options);
    67|                }
    68|                if (showAll || showFiles) {
    69|                    this.printFileList(snapshot, options);
    70|                }
    71|                if (showAll || showSummary) {
    72|                    this.printSummary(snapshot, options);
    73|                }
    74|            }
    75|            return this.success();
    76|        }
    77|        catch (err) {
    78|            return this.error(`Inspect failed: ${err.message}`, options);
    79|        }
    80|    }
    81|    parseArgs(args) {
    82|        const flags = {};
    83|        let filePath;
    84|        for (let i = 0; i < args.length; i++) {
    85|            const arg = args[i];
    86|            switch (arg) {
    87|                case '--metadata':
    88|                case '-m':
    89|                    flags.metadata = true;
    90|                    break;
    91|                case '--structure':
    92|                case '-s':
    93|                    flags.structure = true;
    94|                    break;
    95|                case '--files':
    96|                case '-f':
    97|                    flags.files = true;
    98|                    break;
    99|                case '--summary':
   100|                    flags.summary = true;
   101|                    break;
   102|                default:
   103|                    if (!arg.startsWith('-')) {
   104|                        filePath = arg;
   105|                    }
   106|            }
   107|        }
   108|        return { flags, filePath };
   109|    }
   110|    async readFile(filePath) {
   111|        const { readFileSync } = await import('fs');
   112|        return readFileSync(filePath, 'utf8');
   113|    }
   114|    printMetadata(metadata, options) {
   115|        if (options.json) {
   116|            this.print(metadata, options);
   117|            return;
   118|        }
   119|        console.log('\n📊 SNAPSHOT METADATA');
   120|        console.log('─'.repeat(40));
   121|        printTable(['Property', 'Value'], [
   122|            ['Files', metadata.fileCount.toString()],
   123|            ['Total Size', this.formatBytes(metadata.totalSize)],
   124|            ['Directory Structure Lines', metadata.directoryStructureLines.toString()],
   125|            ['Has Instructions', metadata.hasInstruction ? 'Yes' : 'No'],
   126|            ['Has File Summary', metadata.hasFileSummary ? 'Yes' : 'No'],
   127|            ['Has Custom Header', metadata.hasUserProvidedHeader ? 'Yes' : 'No']
   128|        ], options);
   129|        console.log();
   130|    }
   131|    printStructure(structure, options) {
   132|        if (options.json) {
   133|            this.print({ directoryStructure: structure }, options);
   134|            return;
   135|        }
   136|        console.log('\n📁 DIRECTORY STRUCTURE');
   137|        console.log('─'.repeat(40));
   138|        console.log(structure || '(empty)');
   139|        console.log();
   140|    }
   141|    printFileList(snapshot, options) {
   142|        const files = Object.keys(snapshot.files);
   143|        if (options.json) {
   144|            this.print({ filePaths: files }, options);
   145|            return;
   146|        }
   147|        console.log('\n📄 FILES');
   148|        console.log('─'.repeat(40));
   149|        if (files.length === 0) {
   150|            console.log('(no files)');
   151|        }
   152|        else {
   153|            const fileData = files.map((f) => [
   154|                f,
   155|                this.formatBytes(Buffer.byteLength(snapshot.files[f], 'utf8'))
   156|            ]);
   157|            printTable(['Path', 'Size'], fileData, options);
   158|        }
   159|        console.log();
   160|    }
   161|    printSummary(snapshot, options) {
   162|        if (options.json) {
   163|            const result = {};
   164|            if (snapshot.instruction)
   165|                result.instruction = snapshot.instruction;
   166|            if (snapshot.fileSummary)
   167|                result.fileSummary = snapshot.fileSummary;
   168|            if (snapshot.userProvidedHeader)
   169|                result.userProvidedHeader = snapshot.userProvidedHeader;
   170|            this.print(result, options);
   171|            return;
   172|        }
   173|        if (snapshot.userProvidedHeader) {
   174|            console.log('\n📌 CUSTOM HEADER');
   175|            console.log('─'.repeat(40));
   176|            console.log(snapshot.userProvidedHeader);
   177|            console.log();
   178|        }
   179|        if (snapshot.fileSummary) {
   180|            console.log('\n📝 FILE SUMMARY');
   181|            console.log('─'.repeat(40));
