    27|                const { loadSnapshot } = await import('../utils/streaming-json.js');
    28|                snapshot = await loadSnapshot(context.stdin);
    29|            }
    30|            else {
    31|                return this.error('No snapshot source provided', options);
    32|            }
    33|            // 2. Update file content if provided
    34|            if (filePath) {
    35|                let actualContent = content;
    36|                // If no content in args, look for it in stdin
    37|                if (actualContent === undefined && context.stdinIsPipe) {
    38|                    actualContent = context.stdin;
    39|                }
    40|                if (actualContent !== undefined) {
    41|                    // Check if it's a new file
    42|                    const isNew = snapshot.files[filePath] === undefined;
    43|                    snapshot.files[filePath] = actualContent;
    44|                    if (isNew) {
    45|                        // Simple update to directory structure
    46|                        snapshot.directoryStructure += `\n${filePath}`;
    47|                    }
    48|                }
    49|            }
    50|            // 3. Update metadata if provided
    51|            if (flags.instruction) {
    52|                snapshot.instruction = flags.instruction;
    53|            }
    54|            if (flags.summary) {
    55|                snapshot.fileSummary = flags.summary;
    56|            }
