    65|        }
    66|        catch (err) {
    67|            return this.error(`Patch failed: ${err.message}`, options);
    68|        }
    69|    }
    70|    parseArgs(args) {
    71|        const flags = {};
    72|        const positional = [];
    73|        for (let i = 0; i < args.length; i++) {
    74|            const arg = args[i];
    75|            if (arg === '--instruction') {
