    93|                snapshotFile = positional[0];
    94|            }
    95|            else {
    96|                filePath = positional[0];
    97|            }
    98|        }
    99|        else if (positional.length === 2) {
   100|            if (positional[1].endsWith('.json')) {
   101|                filePath = positional[0];
   102|                snapshotFile = positional[1];
   103|            }
   104|            else {
   105|                filePath = positional[0];
