    38|                    missingFiles.push(filePath);
    39|                }
    40|                else if (lstatSync(localPath).isDirectory()) {
    41|                    // Path in snapshot is a file, but on disk is a directory (unlikely but possible)
    42|                    missingFiles.push(filePath);
    43|                }
    44|                else {
    45|                    const localContent = readFileSync(localPath, 'utf8');
    46|                    if (localContent !== content) {
    47|                        modifiedFiles.push(filePath);
    48|                    }
    49|                }
    50|            }
    51|            // 2. Check for extra local files (optional, we could walker here)
    52|            // This is more expensive, so we might make it an optional flag --all
    53|            if (flags.all) {
    54|                this.findExtraFiles(targetDir, snapshot.files, extraFiles);
    55|            }
    56|            const result = {
    57|                modifiedFiles,
    58|                missingFiles,
    59|                extraFiles,
    60|                targetDir
    61|            };
    62|            if (options.json) {
    63|                const output = JSON.stringify(result, null, 2);
    64|                this.print(result, options);
    65|                return this.success(output);
