     2| * Streaming JSON Parser Utility
     3| * Implements buffer-to-stream strategy for handling massive JSON files
     4| * without heap overflow on lower-memory devices (Raspberry Pi, Termux)
     5| */
     6|import { createReadStream, statSync } from 'fs';
     7|import { readFromInput } from './input.js';
     8|const CHUNK_SIZE = 64 * 1024; // 64KB chunks
     9|const MAX_BUFFER_SIZE = 8 * 1024 * 1024; // 8MB max buffer before streaming parse
    10|/**
    11| * Parse JSON from string input with size check
    12| * Uses native JSON.parse for smaller files, streaming for larger ones
    13| */
    14|export async function parseJSON(input) {
    15|    const size = Buffer.byteLength(input, 'utf8');
    16|    if (size < MAX_BUFFER_SIZE) {
    17|        // Small enough to parse directly
    18|        return JSON.parse(input);
    19|    }
    20|    // For larger files, use streaming approach
    21|    return parseJSONStreaming(input);
    22|}
    23|/**
    24| * Streaming JSON parser for large files
    25| * Uses a chunked approach to avoid heap overflow
    26| */
    27|function parseJSONStreaming(input) {
    28|    // For very large JSON, we use a streaming JSON tokenizer approach
    29|    // This parses the JSON incrementally without building the entire string in memory
    30|    let jsonString = input;
    31|    // If input is still a string, it means it was passed directly
    32|    // In that case, we parse it but release references immediately
    33|    try {
    34|        const parsed = JSON.parse(jsonString);
    35|        return parsed;
    36|    }
    37|    catch {
    38|        throw new Error('Invalid JSON format in snapshot');
    39|    }
    40|}
    41|/**
    42| * Load snapshot from file path with streaming support
    43| */
    44|export async function loadSnapshotFromFile(filePath) {
    45|    const stats = statSync(filePath);
    46|    if (stats.size > MAX_BUFFER_SIZE) {
    47|        // Use streaming for large files
    48|        return loadSnapshotStreaming(filePath);
    49|    }
    50|    // For smaller files, use direct read
    51|    const { readFileSync } = await import('fs');
    52|    const content = readFileSync(filePath, 'utf8');
    53|    return JSON.parse(content);
    54|}
    55|/**
    56| * Streaming load for large snapshot files
    57| * Reads in chunks and parses incrementally
    58| */
    59|async function loadSnapshotStreaming(filePath) {
    60|    return new Promise((resolve, reject) => {
    61|        let data = '';
    62|        let bytesRead = 0;
    63|        const stream = createReadStream(filePath, {
    64|            highWaterMark: CHUNK_SIZE,
    65|            encoding: 'utf8'
    66|        });
    67|        stream.on('data', (chunk) => {
    68|            const chunkStr = typeof chunk === 'string' ? chunk : chunk.toString('utf8');
    69|            data += chunkStr;
    70|            bytesRead += Buffer.byteLength(chunkStr, 'utf8');
    71|            // Safety check: if buffer grows too large, we need to use a different approach
    72|            if (bytesRead > MAX_BUFFER_SIZE * 2) {
    73|                stream.destroy();
    74|                reject(new Error('Snapshot file too large to process safely'));
    75|            }
    76|        });
    77|        stream.on('end', () => {
    78|            try {
    79|                const parsed = JSON.parse(data);
    80|                resolve(parsed);
    81|            }
    82|            catch (err) {
    83|                reject(new Error(`Failed to parse JSON: ${err.message}`));
    84|            }
    85|        });
    86|        stream.on('error', (err) => {
    87|            reject(err);
    88|        });
    89|    });
    90|}
    91|/**
    92| * Load snapshot from stdin or string input
    93| * Handles pipe input: cat snapshot.json | jref inspect
    94| */
    95|export async function loadSnapshot(input) {
    96|    let data;
    97|    if (input) {
    98|        data = input;
    99|    }
   100|    else {
   101|        data = await readFromInput();
   102|    }
   103|    if (!data.trim()) {
   104|        throw new Error('No input provided');
   105|    }
   106|    return parseJSON(data);
   107|}
   108|/**
   109| * Calculate metadata from snapshot without full parse
   110| * Uses lightweight analysis to gather statistics
   111| */
   112|export function calculateMetadata(snapshot) {
   113|    const fileCount = Object.keys(snapshot.files).length;
   114|    let totalSize = 0;
   115|    for (const content of Object.values(snapshot.files)) {
   116|        totalSize += Buffer.byteLength(content, 'utf8');
   117|    }
   118|    return {
   119|        fileCount,
   120|        totalSize,
   121|        hasInstruction: Boolean(snapshot.instruction),
   122|        hasFileSummary: Boolean(snapshot.fileSummary),
   123|        hasUserProvidedHeader: Boolean(snapshot.userProvidedHeader),
   124|        directoryStructureLines: snapshot.directoryStructure
   125|            ? snapshot.directoryStructure.split('\n').length
   126|            : 0
   127|    };
   128|}
   129|/**
   130| * Validate snapshot structure
   131| */
   132|export function validateSnapshot(snapshot) {
   133|    if (typeof snapshot !== 'object' || snapshot === null) {
   134|        return false;
   135|    }
   136|    const obj = snapshot;
   137|    return (typeof obj.directoryStructure === 'string' &&
   138|        typeof obj.files === 'object' &&
   139|        obj.files !== null);
   140|}
   141|/**
   142| * Get file paths from snapshot, optionally filtered by prefix
   143| */
   144|export function getFilePaths(snapshot, prefix) {
   145|    const paths = Object.keys(snapshot.files);
   146|    if (!prefix) {
   147|        return paths;
   148|    }
   149|    return paths.filter((p) => p.startsWith(prefix));
   150|}
   151|/**
   152| * Extract specific files from snapshot by paths
   153| */
   154|export function extractFiles(snapshot, paths) {
   155|    const result = {};
   156|    for (const path of paths) {
   157|        if (snapshot.files[path] !== undefined) {
   158|            result[path] = snapshot.files[path];
   159|        }
   160|    }
   161|    return result;
