    11|// Export for testing
    12|export function buildFlatTree(root, expanded) {
    13|    const items = [];
    14|    // Detect structure: single-container (typical project) vs multi-root (monorepo/workspace)
    15|    const singleContainer = root.children.length === 1 && root.children[0].isDirectory;
    16|    const containerPath = singleContainer ? root.children[0].path : '';
    17|    function traverse(node, depth) {
    18|        // Compute the path used for file lookup and expansion state
    19|        let nodePath;
    20|        if (node === root) {
    21|            nodePath = ''; // dummy root
    22|        }
    23|        else if (singleContainer && node.path.startsWith(containerPath + '/')) {
    24|            // Strip container prefix (e.g., "project/src" -> "src")
    25|            nodePath = node.path.slice(containerPath.length + 1);
    26|        }
    27|        else if (singleContainer && node.path === containerPath) {
    28|            // The container itself
    29|            nodePath = '';
    30|        }
    31|        else {
    32|            // Multi-root or other: use full path as-is
    33|            nodePath = node.path;
    34|        }
    35|        // Add non-root nodes to flat list
    36|        if (node !== root) {
    37|            items.push({
    38|                node: {
    39|                    ...node,
    40|                    path: nodePath
    41|                },
    42|                depth: depth - 1, // Adjust depth so first visible level is at depth 0
    43|                isExpanded: expanded.has(nodePath)
    44|            });
    45|        }
    46|        // Traverse children if this directory is expanded (always traverse dummy root)
    47|        const shouldTraverse = node === root
    48|            ? true
    49|            : node.isDirectory && expanded.has(nodePath);
    50|        if (shouldTraverse) {
    51|            for (const child of node.children) {
    52|                traverse(child, depth + 1);
    53|            }
    54|        }
    55|    }
    56|    traverse(root, 0);
    57|    return items;
    58|}
    59|export function SnapshotBrowser({ tree, files, onExit }) {
    60|    const [selectedIndex, setSelectedIndex] = useState(0);
    61|    const [viewMode, setViewMode] = useState('tree');
    62|    const [selectedFile, setSelectedFile] = useState(null);
    63|    const [scrollOffset, setScrollOffset] = useState(0);
    64|    const [searchQuery, setSearchQuery] = useState('');
    65|    const [searchResults, setSearchResults] = useState([]);
    66|    const [isCompactMode, setIsCompactMode] = useState(false);
    67|    const [statusMessage, setStatusMessage] = useState(null);
    68|    // Initialize expanded directories - include project root (using relative paths)
    69|    const [expandedDirs, setExpandedDirs] = useState(new Set(['']));
    70|    // Toggle directory expansion
    71|    const toggleExpansion = React.useCallback((nodePath) => {
    72|        setExpandedDirs(prev => {
    73|            const newSet = new Set(prev);
    74|            if (newSet.has(nodePath)) {
    75|                newSet.delete(nodePath);
    76|            }
    77|            else {
    78|                newSet.add(nodePath);
    79|            }
    80|            return newSet;
    81|        });
    82|    }, []);
    83|    // Compute flat tree directly (avoid useEffect timing issues)
    84|    const flatTreeItems = React.useMemo(() => {
    85|        return buildFlatTree(tree, expandedDirs);
    86|    }, [tree, expandedDirs]);
    87|    // Adjust selected index if it's out of bounds
    88|    React.useEffect(() => {
    89|        if (selectedIndex >= flatTreeItems.length) {
