    96|            try {
    97|                // Get terminal dimensions
    98|                const { columns = 80 } = process.stdout;
    99|                setIsCompactMode(columns < 60); // Compact mode for narrow screens
   100|            }
   101|            catch {
   102|                setIsCompactMode(false);
   103|            }
   104|        };
   105|        checkScreenSize();
   106|        // Check on resize if available
   107|        const resizeHandler = () => checkScreenSize();
   108|        process.stdout.on?.('resize', resizeHandler);
   109|        return () => {
   110|            process.stdout.off?.('resize', resizeHandler);
   111|        };
   112|    }, []);
