   131|                setSearchQuery('');
   132|                setSearchResults([]);
   133|                setSelectedIndex(0);
   134|            }
   135|            else if (viewMode === 'file') {
   136|                setViewMode('tree');
   137|                setSelectedFile(null);
   138|                setScrollOffset(0);
   139|            }
   140|            else {
   141|                onExit();
   142|            }
   143|            return;
   144|        }
   145|        if (viewMode === 'tree') {
